parameters.jsCode:
let facts = $input.item.json;

// Default flags based on instructions
facts.internal_review_required = false;
facts.client_auto_send_allowed = true; // Assume true until a rule breaks it

// Rule 1: Transcript checks (using metadata passed from earlier nodes)
if (facts.transcript_available === false || facts.transcript_available === "false" || facts.transcript_available === null) {
    facts.internal_review_required = true;
    facts.client_auto_send_allowed = false;
}

// Rule 2: Duration check (Under 5 minutes / 300 seconds)
if (facts.call_duration_seconds < 300) {
    facts.transcript_quality = "low";
    facts.client_auto_send_allowed = false;
}

// Rule 3 & 4: Missing crucial contact info
if (!facts.client_email || facts.client_email === "null" || facts.client_email.trim() === "") {
    facts.client_auto_send_allowed = false;
}
if (!facts.client_company_name || facts.client_company_name === "null" || facts.client_company_name.trim() === "") {
    facts.client_auto_send_allowed = false;
}

// Rule 5: Fewer than 2 pain points
if (!facts.pain_points || facts.pain_points.length < 2) {
    facts.client_auto_send_allowed = false;
}

// Rule 6 & 7: Missing operational data flags internal review
if (!facts.current_systems || facts.current_systems.length === 0 || facts.current_systems[0] === "null") {
    facts.internal_review_required = true;
}
if (!facts.top_business_goal || facts.top_business_goal === "null") {
    facts.internal_review_required = true;
}

// Rule 8: Missing what not to automate
if (!facts.what_not_to_automate || facts.what_not_to_automate === "null") {
    // Flag it in internal report (handled in prompt 3), but we can track it here
    if (!facts.important_missing_fields) facts.important_missing_fields = [];
    facts.important_missing_fields.push("what_not_to_automate");
}

  return { json: facts };

// Extract the Retell payload from the Webhook
const payload = $input.item.json.body.call || {};

// Safely extract all required fields per LA Consulting specifications
const callId = payload.call_id || "No_Call_ID";
const transcript = payload.transcript || "";
const recordingUrl = payload.recording_url || "";
const durationMs = payload.duration_ms || 0;
const durationSeconds = Math.floor(durationMs / 1000);

// Basic quality flags
const transcriptAvailable = transcript.trim().length > 0;
const isCallLongEnough = durationSeconds > 120; // 2 minute threshold for initial gate

return {
  json: {
    call_id: callId,
    transcript: transcript,
    recording_url: recordingUrl,
    duration_seconds: durationSeconds,
    transcript_available: transcriptAvailable,
    is_call_long_enough: isCallLongEnough
  }
};

